    ['2-1-3', 'Acceptable use policy for information and technology assets identification', 'تحديد وتوثيق واعتماد ونشر سياسة الاستخدام المقبول للأصول', 'The policy of acceptable use of information and technology assets of the entity shall be identified, documented, approved, and communicated.', 'يجب تحديد وتوثيق واعتماد ونشر سياسة الاستخدام المقبول للأصول المعلوماتية والتقنية للجهة.', '2-1', 3, '19'],
    ['2-1-4', 'Acceptable use policy for information and technology assets implementation', 'تطبيق سياسة الاستخدام المقبول للأصول', 'The policy of acceptable use of information and technology assets of the entity shall be implemented.', 'يجب تطبيق سياسة الاستخدام المقبول للأصول المعلوماتية والتقنية للجهة.', '2-1', 4, '19'],
    ['2-1-5', 'Information and technology assets classification, labeling, and handling', 'تصنيف الأصول المعلوماتية والتقنية وترميزها والتعامل معها', 'Information and technology assets of the entity shall be classified, labeled, and handled as per the relevant legislative and regulatory requirements.', 'يجب تصنيف الأصول المعلوماتية والتقنية للجهة وترميزها (Labeling) والتعامل معها وفقاً للمتطلبات التشريعية والتنظيمية ذات العلاقة.', '2-1', 5, '19'],
