    // 2-2 Identity and Access Management (page 19)
    ['2-2-1', 'Cybersecurity requirements for identity and access management identification', 'تحديد وتوثيق واعتماد متطلبات إدارة هويات الدخول والصلاحيات', 'Cybersecurity requirements for identity and access management of the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لإدارة هويات الدخول والصلاحيات في الجهة.', '2-2', 7, '19'],
    ['2-2-2', 'Cybersecurity requirements for identity and access management implementation', 'تطبيق متطلبات إدارة هويات الدخول والصلاحيات', 'Cybersecurity requirements for identity and access management of the entity shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني لإدارة هويات الدخول والصلاحيات في الجهة.', '2-2', 8, '19'],
    ['2-2-3', 'Identity and access management requirements coverage', 'متطلبات إدارة هويات الدخول والصلاحيات', "Cybersecurity requirements for identity and access management of the entity shall include the following as a minimum:\n2.2.3.1 Single-factor authentication based on username and password.\n2.2.3.2 Multi-factor authentication, and defining the suitable authentication factors and their numbers as well as the suitable authentication techniques based on the result of impact assessment of authentication failure and bypass for remote access and for privileged accounts.\n2.2.3.3 User authorization based on identity and access control principles (Need-to Know and Need-to-Use principle, Least Privilege principle, and Segregation of Duties principle).\n2.2.3.4 Privileged access management.\n2.2.3.5 Periodic review of identities and access rights.", 'يجب أن تغطي متطلبات الأمن السيبراني المتعلقة بإدارة هويات الدخول والصلاحيات في الجهة بحد أدنى ما يلي: 1-3-2-2 التحقق من الهوية أحادي العنصر (Single-factor authentication) بناءً على إدارة تسجيل المستخدم، وإدارة كلمة المرور. 2-3-2-2 التحقق من الهوية متعدد العناصر (Multi-Factor Authentication) وتحديد عناصر التحقق المناسبة وعددها وكذلك تقنيات التحقق المناسبة بناء على نتائج تقييم الأثر المحتمل لفشل عملية التحقق وتخطيها، وذلك لعمليات الدخول عن بعد. 3-3-2-2 إدارة تصاريح وصلاحيات المستخدمين (Authorization) بناءً على مبادئ التحكم بالدخول والصلاحيات (مبدأ الحاجة إلى المعرفة والاستخدام "Need-to-know and Need-to-use"، ومبدأ الحد الأدنى من الصلاحيات والامتيازات "Least Privilege"، ومبدأ فصل المهام "Segregation of Duties"). 4-3-2-2 إدارة الصلاحيات الهامة والحساسة (Privileged Access Management). 5-3-2-2 المراجعة الدورية لهويات الدخول والصلاحيات.', '2-2', 9, '19'],
    ['2-2-4', 'Identity and access management requirements implementation review', 'مراجعة تطبيق متطلبات إدارة هويات الدخول والصلاحيات', 'The implementation of cybersecurity requirements for identity and access management of the entity shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات الأمن السيبراني لإدارة هويات الدخول والصلاحيات في الجهة دورياً.', '2-2', 10, '19'],

    // 2-3 Information System and Processing Facilities Protection (page 20)
    ['2-3-1', 'Cybersecurity requirements for protection of information systems and processing facilities identification', 'تحديد وتوثيق واعتماد متطلبات حماية الأنظمة وأجهزة معالجة المعلومات', 'Cybersecurity requirements for protection of information system and processing facilities of the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لحماية الأنظمة وأجهزة معالجة المعلومات للجهة.', '2-3', 11, '20'],
    ['2-3-2', 'Cybersecurity requirements for protection of information systems and processing facilities implementation', 'تطبيق متطلبات حماية الأنظمة وأجهزة معالجة المعلومات', 'Cybersecurity requirements for protection of information systems and processing facilities of the entity shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني لحماية الأنظمة وأجهزة معالجة المعلومات للجهة.', '2-3', 12, '20'],
    ['2-3-3', 'Information systems and processing facilities protection requirements coverage', 'متطلبات حماية الأنظمة وأجهزة معالجة المعلومات', "Cybersecurity requirements for protection of information systems and processing facilities of the entity shall include the following as a minimum:\n2.3.3.1 Protection from viruses, suspicious programs and activities, and malware on workstations and servers, using modern and advanced protection technologies and mechanisms, and securely managing them.\n2.3.3.2 Strict restriction on the use of external storage media and their security.\n2.3.3.3 Patch management for systems, applications, and devices.\n2.3.3.4 Centralized clock synchronization with an accurate and trusted source, such as sources provided by the Saudi Standards, Metrology and Quality Organization (SASO).", 'يجب أن تغطي متطلبات الأمن السيبراني لحماية الأنظمة وأجهزة معالجة المعلومات للجهة بحد أدنى ما يلي: 1-3-3-2 الحماية من الفيروسات والبرامج والأنشطة المشبوهة والبرمجيات الضارة (Malware) على أجهزة المستخدمين والخوادم باستخدام تقنيات وآليات الحماية الحديثة والمتقدمة، وإدارتها بشكل آمن. 2-3-3-2 التقييد الحازم لاستخدام أجهزة وسائط التخزين الخارجية والأمن المتعلق بها. 3-3-3-2 إدارة حزم التحديثات والإصلاحات للأنظمة والتطبيقات والأجهزة (Patch Management). 4-3-3-2 مزامنة التوقيت (Clock Synchronization) مركزياً ومن مصدر دقيق وموثوق، ومن هذه المصادر ما توفره الهيئة السعودية للمواصفات والمقاييس والجودة.', '2-3', 13, '20'],
    ['2-3-4', 'Information systems and processing facilities protection requirements review', 'مراجعة متطلبات حماية الأنظمة وأجهزة معالجة المعلومات', 'The implementation of cybersecurity requirements for protection of the information system and processing facilities of the entity shall be periodically reviewed.', 'يجب مراجعة متطلبات الأمن السيبراني لحماية الأنظمة وأجهزة معالجة المعلومات للجهة دورياً.', '2-3', 14, '20'],

    // 2-4 Email Protection (page 20)
    ['2-4-1', 'Cybersecurity requirements for protection of the email service identification', 'تحديد وتوثيق واعتماد متطلبات حماية البريد الإلكتروني', 'Cybersecurity requirements for protection of the email service of the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لحماية البريد الإلكتروني للجهة.', '2-4', 15, '20'],
    ['2-4-2', 'Cybersecurity requirements for protection of email service implementation', 'تطبيق متطلبات حماية البريد الإلكتروني', 'Cybersecurity requirements for protection of email service of the entity shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني لحماية البريد الإلكتروني للجهة.', '2-4', 16, '20'],
    ['2-4-3', 'Email protection requirements coverage', 'متطلبات حماية البريد الإلكتروني', "Cybersecurity requirements for protection of the email service of the entity shall include the following as a minimum:\n2.4.3.1 Analyzing and filtering email messages (specifically phishing emails and spam emails) using modern and advanced email protection techniques and mechanisms.\n2.4.3.2 Multi-factor authentication, and defining the suitable authentication factors and their numbers as well as the suitable authentication techniques based on the result of impact assessment of authentication failure and bypass for remote and webmail access.\n2.4.3.3 Email archiving and backup.\n2.4.3.4 Secure management and protection against Advanced Persistent Threats (APT), which normally utilize zero-day malware and viruses.\n2.4.3.5 Validation of the entity's email service domains by using Sender Policy Framework (SPF), Domain Keys Identified Mail (DKIM), and Domain Message Authentication Reporting and Conformance (DMARC).", 'يجب أن تغطي متطلبات الأمن السيبراني لحماية البريد الإلكتروني للجهة بحد أدنى ما يلي: 1-3-4-2 تحليل وتصفية (Filtering) رسائل البريد الإلكتروني (وخصوصاً رسائل التصيّد الإلكتروني "Phishing Emails" والرسائل الإقتحامية "Spam Emails") باستخدام تقنيات وآليات الحماية الحديثة والمتقدمة للبريد الإلكتروني. 2-3-4-2 التحقق من الهوية متعدد العناصر (Multi-Factor Authentication) وتحديد عناصر التحقق المناسبة وعددها وكذلك تقنيات التحقق المناسبة بناء على نتائج تقييم الأثر المحتمل لفشل عملية التحقق وتخطيها، وذلك للدخول عن بعد والدخول عن طريق صفحة موقع البريد الإلكتروني (Webmail). 3-3-4-2 النسخ الاحتياطي والأرشفة للبريد الإلكتروني. 4-3-4-2 الحماية من التهديدات المتقدمة المستمرة (APT Protection)، التي تستخدم عادة الفيروسات والبرمجيات الضارة غير المعروفة مسبقاً (Zero-Day Malware)، وإدارتها بشكل آمن. 5-3-4-2 توثيق مجال البريد الإلكتروني للجهة من خلال منصة حصين باستخدام إطار سياسة المرسل (Sender Policy Framework "SPF") والبريد المعرّف بمفاتيح النطاق (Domain Keys Identified Mail "DKIM") وسياسة مصادقة الرسائل والإبلاغ عنها (Domain Message Authentication Reporting and Conformance "DMARC").', '2-4', 17, '20'],
    ['2-4-4', 'Email service protection requirements implementation review', 'مراجعة تطبيق متطلبات حماية البريد الإلكتروني', 'The implementation of cybersecurity requirements for email service of the entity shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات الأمن السيبراني الخاصة بحماية البريد الإلكتروني للجهة دورياً.', '2-4', 18, '20'],

    // 2-5 Networks Security Management (page 21)
    ['2-5-1', 'Cybersecurity requirements for network security management identification', 'تحديد وتوثيق واعتماد متطلبات إدارة أمن الشبكات', 'Cybersecurity requirements for the entity\'s network security management shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لإدارة أمن شبكات الجهة.', '2-5', 19, '21'],
    ['2-5-2', 'Cybersecurity requirements for network security management implementation', 'تطبيق متطلبات إدارة أمن الشبكات', 'Cybersecurity requirements for the entity\'s network security management shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني لإدارة أمن شبكات الجهة.', '2-5', 20, '21'],
    ['2-5-3', 'Network security management requirements coverage', 'متطلبات إدارة أمن الشبكات', "Cybersecurity requirements for the entity's network security management shall include the following as a minimum:\n2.5.3.1 Logical or physical isolation and segmentation of network segments in a secure manner which is required to control relevant cybersecurity risks, using firewall and defense-in-depth principle.\n2.5.3.2 Isolation of production network from testing and development environment networks.\n2.5.3.3 Secure browsing and internet connectivity, including strict restrictions on suspicious websites, file storage/sharing websites, and remote access websites.\n2.5.3.4 Wireless network security and protection using secure authentication and encryption techniques and avoiding the connection of wireless networks to the entity's internal network, except after a comprehensive assessment of subsequent risks, with handling them in a way that protects the technology assets of the entity.\n2.5.3.5 Restricting and managing network services, protocols, and ports.\n2.5.3.6 Intrusion Prevention Systems (IPS).\n2.5.3.7 Security of Domain Name Service (DNS).\n2.5.3.8 Secure management and protection of Internet browsing channel against Advanced Persistent Threats (APT), which normally utilize zero-day malware and viruses.\n2.5.3.9 Protecting against Distributed Denial of Service (DDoS) attacks to limit risks arising from these attacks.", 'يجب أن تغطي متطلبات الأمن السيبراني لإدارة أمن شبكات الجهة بحد أدنى ما يلي: 1-3-5-2 العزل والتقسيم المادي أو المنطقي لأجزاء الشبكات بشكل آمن، واللازم للسيطرة على مخاطر الأمن السيبراني ذات العلاقة، باستخدام جدار الحماية (Firewall) ومبدأ الدفاع الأمني متعدد المراحل (Defense-in-Depth). 2-3-5-2 عزل شبكة بيئة الإنتاج عن شبكات بيئات التطوير والاختبار. 3-3-5-2 أمن التصفح والاتصال بالإنترنت، ويشمل ذلك التقييد الحازم للمواقع الإلكترونية المشبوهة، ومواقع مشاركة وتخزين الملفات، ومواقع الدخول عن بعد. 4-3-5-2 أمن الشبكات اللاسلكية وحمايتها باستخدام وسائل آمنة للتحقق من الهوية والتشفير، وعدم ربط الشبكات اللاسلكية بشبكة الجهة الداخلية إلا بناءً على دراسة متكاملة للمخاطر المترتبة على ذلك والتعامل معها بما يضمن حماية الأصول التقنية للجهة. 5-3-5-2 قيود وإدارة منافذ وبروتوكولات وخدمات الشبكة. 6-3-5-2 أنظمة الحماية المتقدمة لاكتشاف ومنع الاختراقات (Intrusion Prevention Systems). 7-3-5-2 أمن نظام أسماء النطاقات (DNS). 8-3-5-2 حماية قناة تصفح الإنترنت من التهديدات المتقدمة المستمرة (APT Protection)، التي تستخدم عادة الفيروسات والبرمجيات الضارة غير المعروفة مسبقاً (Zero-Day Malware)، وإدارتها بشكل آمن. 9-3-5-2 الحماية من هجمات تعطيل الشبكات (Distributed Denial of Service Attack "DDoS") للحد من المخاطر الناتجة عن هجمات تعطيل الشبكات.', '2-5', 21, '21'],
    ['2-5-4', 'Network security management requirements implementation review', 'مراجعة تطبيق متطلبات إدارة أمن الشبكات', 'The implementation of cybersecurity requirements for the entity\'s network security management shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات الأمن السيبراني لإدارة أمن شبكات الجهة دورياً.', '2-5', 22, '21'],

    // 2-6 Mobile Devices Security (page 22)
    ['2-6-1', 'Cybersecurity requirements for mobile devices and BYOD security identification', 'تحديد وتوثيق واعتماد متطلبات أمن الأجهزة المحمولة وBYOD', 'Cybersecurity requirements for mobile devices and BYOD security when connected to the entity\'s network shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني الخاصة بأمن الأجهزة المحمولة والأجهزة الشخصية للعاملين (BYOD) عند ارتباطها بشبكة الجهة.', '2-6', 23, '22'],
    ['2-6-2', 'Cybersecurity requirements for mobile devices and BYOD security implementation', 'تطبيق متطلبات أمن الأجهزة المحمولة وBYOD', 'Cybersecurity requirements for mobile devices and BYOD security of the entity shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني الخاصة بأمن الأجهزة المحمولة وأجهزة (BYOD) للجهة.', '2-6', 24, '22'],
    ['2-6-3', 'Mobile devices and BYOD security requirements coverage', 'متطلبات أمن الأجهزة المحمولة وBYOD', "Cybersecurity requirements for mobile devices and BYOD security of the entity shall include the following as a minimum:\n2.6.3.1 Separation and encryption of the entity's data and information stored on mobile devices and BYODs.\n2.6.3.2 Controlled and restricted use based on the requirements of the interest of the entity's business.\n2.6.3.3 Deletion of the entity's data and information stored on mobile devices and BYOD in cases of device loss or after the ending/termination of employment with the entity.\n2.6.3.4 Security awareness for users.", 'يجب أن تغطي متطلبات الأمن السيبراني الخاصة بأمن الأجهزة المحمولة وأجهزة (BYOD) للجهة بحد أدنى ما يلي: 1-3-6-2 فصل وتشفير البيانات والمعلومات (الخاصة بالجهة) المخزنة على الأجهزة المحمولة وأجهزة (BYOD). 2-3-6-2 الاستخدام المحدد والمقيد بناءً على ما تتطلبه مصلحة أعمال الجهة. 3-3-6-2 حذف البيانات والمعلومات (الخاصة بالجهة) المخزنة على الأجهزة المحمولة وأجهزة (BYOD) عند فقدان الأجهزة أو بعد انتهاء/إنهاء العلاقة الوظيفية مع الجهة. 4-3-6-2 التوعية الأمنية للمستخدمين.', '2-6', 25, '22'],
    ['2-6-4', 'Mobile devices and BYOD security requirements implementation review', 'مراجعة تطبيق متطلبات أمن الأجهزة المحمولة وBYOD', 'The implementation of cybersecurity requirements for mobile devices and BYOD security of the entity shall be periodically reviewed.', 'يجب مراجعة تطبيق متكلبات الأمن السيبراني الخاصة لأمن الأجهزة المحمولة و أجهزة (BYOD) للجهة دورياً.', '2-6', 26, '22'],

