    ['2-8-1', 'Cybersecurity requirements for cryptography identification', 'تحديد وتوثيق واعتماد متطلبات التشفير', 'Cybersecurity requirements for cryptography within the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني للتشفير في الجهة.', '2-8', 30, '23'],
    ['2-8-2', 'Cybersecurity requirements for cryptography implementation', 'تطبيق متطلبات التشفير', 'Cybersecurity requirements for cryptography within the entity shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني للتشفير في الجهة.', '2-8', 31, '23'],
    ['2-8-3', 'Cryptography requirements coverage', 'متطلبات التشفير', "Cybersecurity requirements for cryptography shall include at least the requirements in the National Cryptographic Standards, published by NCA. The appropriate cryptographic standard level shall be implemented based on the nature and sensitivity of the data, systems, and networks to be protected as well as the entity's risk assessment, and as per the relevant legislative and regulatory requirements, as follows:\n2.8.3.1 Approved cryptographic systems and solutions standards and their technical and regulatory restrictions.\n2.8.3.2 Secure management of cryptographic keys during their lifecycles.\n2.8.3.3 Encryption of data in-transit and at-rest, as per their classification and the relevant legislative and regulatory requirements.", 'يجب أن تغطي متطلبات الأمن السيبراني للتشفير بحد أدنى المتطلبات المذكورة في المعايير الوطنية للتشفير الصادرة من الهيئة، مع تطبيق مستوى التشفير المناسب، وذلك بحسب طبيعة ومستوى حساسية البيانات والأنظمة والشبكات وبناءً على تقييم المخاطر من قبل الجهة وحسب المتطلبات التشريعية والتنظيمية ذات العلاقة، وفقاً لما يلي: 1-3-8-2 معايير أنظمة وحلول التشفير المعتمدة والقيود المطبقة عليها (تقنياً وتنظيمياً). 2-3-8-2 الإدارة الآمنة لمفاتيح التشفير خلال عمليات دورة حياتها. 3-3-8-2 تشفير البيانات أثناء النقل والتخزين والمعالجة بناءً على تصنيفها وحسب المتطلبات التشريعية والتنظيمية ذات العلاقة.', '2-8', 32, '23'],
    ['2-8-4', 'Cryptography requirements implementation review', 'مراجعة تطبيق متطلبات التشفير', 'The implementation of cybersecurity requirements for cryptography within the entity shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات الأمن السيبراني للتشفير في الجهة دورياً.', '2-8', 33, '23'],

    // 2-9 Backup and Recovery Management (page 24)
    ['2-9-1', 'Cybersecurity requirements for backup and recovery management identification', 'تحديد وتوثيق واعتماد متطلبات إدارة النسخ الاحتياطية', 'Cybersecurity requirements for backup and recovery management within the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لإدارة النسخ الاحتياطية للجهة.', '2-9', 34, '24'],
    ['2-9-2', 'Cybersecurity requirements for backup and recovery management implementation', 'تطبيق متطلبات إدارة النسخ الاحتياطية', 'Cybersecurity requirements for backup and recovery management within the entity shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني لإدارة النسخ الاحتياطية للجهة.', '2-9', 35, '24'],
    ['2-9-3', 'Backup and recovery management requirements coverage', 'متطلبات إدارة النسخ الاحتياطية', "Cybersecurity requirements for backup and recovery management shall include the following as a minimum:\n2.9.3.1 Scope of backups to cover critical technology and information assets.\n2.9.3.2 Ability to perform quick recovery of data and systems after cybersecurity incidents.\n2.9.3.3 Periodic testing for the effectiveness of backup recovery.", 'يجب أن تغطي متطلبات الأمن السيبراني لإدارة النسخ الاحتياطية بحد أدنى ما يلي: 1-3-9-2 نطاق النسخ الاحتياطية وشموليتها للأصول المعلوماتية والتقنية الحساسة. 2-3-9-2 القدرة السريعة على استعادة البيانات والأنظمة بعد التعرض لحوادث الأمن السيبراني. 3-3-9-2 إجراء فحص دوري لمدى فعالية استعادة النسخ الاحتياطية.', '2-9', 36, '24'],
    ['2-9-4', 'Backup and recovery management requirements implementation review', 'مراجعة تطبيق متطلبات إدارة النسخ الاحتياطية', 'The implementation of cybersecurity requirements for backup and recovery management within the entity shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات الأمن السيبراني لإدارة النسخ الاحتياطية للجهة.', '2-9', 37, '24'],

    // 2-10 Vulnerabilities Management (page 24)
    ['2-10-1', 'Cybersecurity requirements for technical vulnerabilities management identification', 'تحديد وتوثيق واعتماد متطلبات إدارة الثغرات التقنية', 'Cybersecurity requirements for technical vulnerabilities management within the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لإدارة الثغرات التقنية للجهة.', '2-10', 38, '24'],
    ['2-10-2', 'Cybersecurity requirements for technical vulnerabilities management implementation', 'تطبيق متطلبات إدارة الثغرات التقنية', 'Cybersecurity requirements for technical vulnerabilities management within the entity shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني لإدارة الثغرات التقنية للجهة.', '2-10', 39, '24'],
    ['2-10-3', 'Technical vulnerabilities management requirements coverage', 'متطلبات إدارة الثغرات', "Cybersecurity requirements for technical vulnerabilities management shall include the following as a minimum:\n2.10.3.1 Periodic vulnerabilities assessment and detection.\n2.10.3.2 Vulnerabilities classification based on their severities.\n2.10.3.3 Vulnerabilities remediation based on their classification and the associated cyber risks.\n2.10.3.4 Patch management to remediate vulnerabilities, and ensuring the integrity and effectiveness of these updates and fixes are verified using a non-production environment before being applied.\n2.10.3.5 Communication and subscription with trusted resources for new and up-to date vulnerabilities.", 'يجب أن تغطي متطلبات الأمن السيبراني لإدارة الثغرات بحد أدنى ما يلي: 1-3-10-2 فحص واكتشاف الثغرات دورياً. 2-3-10-2 تصنيف الثغرات حسب خطورتها. 3-3-10-2 معالجة الثغرات بناءً على تصنيفها والمخاطر السيبرانية المترتبة عليها. 4-3-10-2 إدارة حزم التحديثات والإصلاحات الأمنية لمعالجة الثغرات، على أن يتم التحقق من سلامة وفعالية تلك التحديثات والإصلاحات الأمنية على بيئة غير بيئة الإنتاج قبل تطبيقها. 5-3-10-2 التواصل والاشتراك مع مصادر موثوقة فيما يتعلق بالتنبيهات المتعلقة بالثغرات الجديدة والمحدثة.', '2-10', 40, '24'],
    ['2-10-4', 'Technical vulnerabilities management requirements implementation review', 'مراجعة تطبيق متطلبات إدارة الثغرات التقنية', 'The implementation of cybersecurity requirements for technical vulnerabilities management within the entity shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات الأمن السيبراني لإدارة الثغرات التقنية للجهة دورياً.', '2-10', 41, '24'],

    // 2-11 Penetration Testing (page 25)
    ['2-11-1', 'Cybersecurity requirements for penetration testing identification', 'تحديد وتوثيق واعتماد متطلبات اختبار الاختراق', 'Cybersecurity requirements for penetration testing within the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لعمليات اختبار الاختراق في الجهة.', '2-11', 42, '25'],
    ['2-11-2', 'Cybersecurity requirements for penetration testing implementation', 'تنفيذ عمليات اختبار الاختراق', 'Cybersecurity requirements for penetration testing within the entity shall be implemented.', 'يجب تنفيذ عمليات اختبار الاختراق في الجهة.', '2-11', 43, '25'],
    ['2-11-3', 'Penetration testing requirements coverage', 'متطلبات اختبار الاختراق', "Cybersecurity requirements for penetration testing shall include the following as a minimum:\n2.11.3.1 Scope of penetration testing to include all externally provided services (via the Internet) and their technical components, including infrastructure, websites, web applications, smartphone and tablet applications, email, and remote access.\n2.11.3.2 Conducting penetration tests periodically.", 'يجب أن تغطي متطلبات الأمن السيبراني لاختبار الاختراق بحد أدنى ما يلي: 1-3-11-2 نطاق عمل اختبار الاختراق، ليشمل جميع الخدمات المقدمة خارجياً (عن طريق الإنترنت) ومكوناتها التقنية، ومنها: البنية التحتية، المواقع الإلكترونية، تطبيقات الويب، تطبيقات الهواتف الذكية واللوحية، البريد الإلكتروني والدخول عن بعد. 2-3-11-2 عمل اختبار الاختراق دورياً.', '2-11', 44, '25'],
    ['2-11-4', 'Penetration testing requirements implementation review', 'مراجعة تطبيق متطلبات اختبار الاختراق', 'The implementation of cybersecurity requirements for penetration testing shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات الأمن السيبراني لعمليات اختبار الاختراق في الجهة دورياً.', '2-11', 45, '25'],

    // 2-12 Cybersecurity Event Logs and Monitoring Management (page 26)
    ['2-12-1', 'Cybersecurity event logs and monitoring management requirements identification', 'تحديد وتوثيق واعتماد متطلبات إدارة سجلات الأحداث ومراقبة الأمن السيبراني', 'Cybersecurity requirements for cybersecurity event logs and monitoring management within the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات إدارة سجلات الأحداث ومراقبة الأمن السيبراني للجهة.', '2-12', 46, '26'],
    ['2-12-2', 'Cybersecurity event logs and monitoring management requirements implementation', 'تطبيق متطلبات إدارة سجلات الأحداث ومراقبة الأمن السيبراني', 'Cybersecurity requirements for cybersecurity event logs and monitoring management within the entity shall be implemented.', 'يجب تطبيق متطلبات إدارة سجلات الأحداث ومراقبة الأمن السيبراني للجهة.', '2-12', 47, '26'],
    ['2-12-3', 'Cybersecurity event logs and monitoring management requirements coverage', 'متطلبات إدارة سجلات الأحداث ومراقبة الأمن السيبراني', "Cybersecurity requirements for cybersecurity event logs and monitoring management shall include the following as a minimum:\n2.12.3.1 Activation of cybersecurity event logs for critical information assets within the entity.\n2.12.3.2 Activation of cybersecurity event logs for critical and privileged accounts accessing information assets as well as for remote access events within the entity.\n2.12.3.3 Identification of Security Information and Event Management (SIEM) techniques required for cybersecurity event logs collection.\n2.12.3.4 Continuous monitoring of cybersecurity event logs.\n2.12.3.5 Retention period of cybersecurity event logs (shall be at least 12 months).", 'يجب أن تغطي متطلبات إدارة سجلات الأحداث ومراقبة الأمن السيبراني بحد أدنى ما يلي: 1-3-12-2 تفعيل سجلات الأحداث (Event logs) الخاصة بالأمن السيبراني على الأصول المعلوماتية الحساسة لدى الجهة. 2-3-12-2 تفعيل سجلات الأحداث الخاصة بالحسابات ذات الصلاحيات الهامة والحساسة على الأصول المعلوماتية وأحداث عمليات الدخول عن بعد لدى الجهة. 3-3-12-2 تحديد التقنيات اللازمة (SIEM) لجمع سجلات الأحداث الخاصة بالأمن السيبراني. 4-3-12-2 المراقبة المستمرة لسجلات الأحداث الخاصة بالأمن السيبراني. 5-3-12-2 مدة الاحتفاظ بسجلات الأحداث الخاصة بالأمن السيبراني (على ألا تقل عن 12 شهر).', '2-12', 48, '26'],
    ['2-12-4', 'Cybersecurity event logs and monitoring management requirements implementation review', 'مراجعة تطبيق متطلبات إدارة سجلات الأحداث ومراقبة الأمن السيبراني', 'The implementation of cybersecurity requirements for cybersecurity event logs and monitoring management within the entity shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات إدارة سجلات الأحداث ومراقبة الأمن السيبراني في الجهة دورياً.', '2-12', 49, '26'],

    // 2-13 Cybersecurity Incident and Threat Management (page 26)
    ['2-13-1', 'Cybersecurity incident and threat management requirements identification', 'تحديد وتوثيق واعتماد متطلبات إدارة حوادث وتهديدات الأمن السيبراني', 'Requirements for cybersecurity incident and threat management within the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات إدارة حوادث وتهديدات الأمن السيبراني في الجهة.', '2-13', 50, '26'],
    ['2-13-2', 'Cybersecurity incident and threat management requirements implementation', 'تطبيق متطلبات إدارة حوادث وتهديدات الأمن السيبراني', 'Requirements for cybersecurity incident and threat management within the entity shall be implemented.', 'يجب تطبيق متطلبات إدارة حوادث وتهديدات الأمن السيبراني في الجهة.', '2-13', 51, '26'],
    ['2-13-3', 'Cybersecurity incident and threat management requirements coverage', 'متطلبات إدارة حوادث وتهديدات الأمن السيبراني', "Requirements for cybersecurity incident and threat management shall include the following as a minimum:\n2.13.3.1 Cybersecurity incident response plans and escalation procedures.\n2.13.3.2 Cybersecurity incident classification.\n2.13.3.3 Reporting cybersecurity incidents to the NCA.\n2.13.3.4 Sharing cybersecurity incident notifications, threat intelligence, penetration indicators, and incident reports with the NCA.\n2.13.3.5 Collecting and handling threat intelligence feeds.", 'يجب أن تغطي متطلبات إدارة حوادث وتهديدات الأمن السيبراني بحد أدنى ما يلي: 1-3-13-2 وضع خطط الاستجابة للحوادث الأمنية وآليات التصعيد. 2-3-13-2 تصنيف حوادث الأمن السيبراني. 3-3-13-2 تبليغ الهيئة عند حدوث حادثة أمن سيبراني. 4-3-13-2 مشاركة التنبيهات والمعلومات الاستباقية ومؤشرات الاختراق وتقارير حوادث الأمن السيبراني مع الهيئة. 5-3-13-2 الحصول على المعلومات الاستباقية (Threat Intelligence) والتعامل معها.', '2-13', 52, '26'],
    ['2-13-4', 'Cybersecurity incident and threat management requirements implementation review', 'مراجعة تطبيق متطلبات إدارة حوادث وتهديدات الأمن السيبراني', 'The implementation of cybersecurity requirements for incident and threat management within the entity shall be periodically reviewed.', 'يجب مراجعة تطبيق متطلبات إدارة حوادث وتهديدات الأمن السيبراني في الجهة دورياً.', '2-13', 53, '26'],

    // 2-14 Physical Security (page 27)
    ['2-14-1', 'Cybersecurity requirements for physical protection of information and technology assets identification', 'تحديد وتوثيق واعتماد متطلبات الحماية المادية للأصول', 'Cybersecurity requirements for protection of information and technology assets of the entity against unauthorized physical access, loss, theft, and damage shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لحماية الأصول المعلوماتية والتقنية للجهة من الوصول المادي غير المصرح به والفقدان والسرقة والتخريب.', '2-14', 54, '27'],
    ['2-14-2', 'Cybersecurity requirements for physical protection of information and technology assets implementation', 'تطبيق متطلبات الحماية المادية للأصول', 'Cybersecurity requirements for protection of information and technology assets of the entity against unauthorized physical access, loss, theft, and damage shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني لحماية الأصول المعلوماتية والتقنية للجهة من الوصول المادي غير المصرح به والفقدان والسرقة والتخريب.', '2-14', 55, '27'],
    ['2-14-3', 'Physical protection of information and technology assets requirements coverage', 'متطلبات الحماية المادية للأصول', "Cybersecurity requirements for protection of information and technology assets of the entity against unauthorized physical access, loss, theft, and damage shall include the following as a minimum:\n2.14.3.1 Authorized access to critical areas within the entity (e.g. the entity's data center, disaster recovery center, critical information processing facilities, security surveillance center, network connection rooms, technical device and equipment supply areas, etc.).\n2.14.3.2 Access and monitoring logs (CCTV).\n2.14.3.3 Protection of access and monitoring log information.\n2.14.3.4 Security of the destruction and re-use of physical assets that hold classified information (including paper documents and storage media).\n2.14.3.5 Security of devices and equipment inside and outside the entity's facilities.", 'يجب أن تغطي متطلبات الأمن السيبراني لحماية الأصول المعلوماتية والتقنية للجهة من الوصول المادي غير المصرح به والفقدان والسرقة والتخريب بحد أدنى ما يلي: 1-3-14-2 الدخول المصرح به للأماكن الحساسة في الجهة (مثل: مركز بيانات الجهة، مركز التعافي من الكوارث، أماكن معالجة المعلومات الحساسة، مركز المراقبة الأمنية، غرف اتصالات الشبكة، مناطق الإمداد الخاصة بالأجهزة والعتاد التقنية، وغيرها). 2-3-14-2 سجلات الدخول والمراقبة (CCTV). 3-3-14-2 حماية معلومات سجلات الدخول والمراقبة. 4-3-14-2 أمن إتلاف وإعادة استخدام الأصول المادية التي تحوي معلومات مصنفة (وتشمل: الوثائق الورقية ووسائط الحفظ والتخزين). 5-3-14-2 أمن الأجهزة والمعدات داخل مباني الجهة وخارجها.', '2-14', 56, '27'],
    ['2-14-4', 'Physical protection of information and technology assets requirements review', 'مراجعة متطلبات الحماية المادية للأصول', 'Cybersecurity requirements for protection of information and technology assets of the entity against unauthorized physical access, loss, theft, and damage shall be periodically reviewed.', 'يجب مراجعة متطلبات الأمن السيبراني لحماية الأصول المعلوماتية والتقنية للجهة من الوصول المادي غير المصرح به والفقدان والسرقة والتخريب دورياً.', '2-14', 57, '27'],

    // 2-15 Web Application Security (page 28)
    ['2-15-1', 'Cybersecurity requirements for protection of external web applications identification', 'تحديد وتوثيق واعتماد متطلبات حماية تطبيقات الويب الخارجية', 'Cybersecurity requirements for protection of external web applications of the entity shall be identified, documented, and approved.', 'يجب تحديد وتوثيق واعتماد متطلبات الأمن السيبراني لحماية تطبيقات الويب الخارجية للجهة من المخاطر السيبرانية.', '2-15', 58, '28'],
    ['2-15-2', 'Cybersecurity requirements for protection of external web applications implementation', 'تطبيق متطلبات حماية تطبيقات الويب الخارجية', 'Cybersecurity requirements for protection of external web applications of the entity shall be implemented.', 'يجب تطبيق متطلبات الأمن السيبراني لحماية تطبيقات الويب الخارجية للجهة.', '2-15', 59, '28'],
    ['2-15-3', 'External web application protection requirements coverage', 'متطلبات حماية تطبيقات الويب الخارجية', "Cybersecurity requirements for protection of external web applications of the entity shall include the following as a minimum:\n2.15.3.1 Use of web application firewall.\n2.15.3.2 Adoption of the multi-tier architecture principle.\n2.15.3.3 Use of secure protocols (e.g. HTTPS).\n2.15.3.4 Clarification of the secure usage policy for users.\n2.15.3.5 User authentication, and the suitable authentication factors and their numbers as well as the authentication techniques shall be defined based on the result of impact assessment of authentication failure and bypass for users' access.", 'يجب أن تغطي متطلبات الأمن السيبراني لحماية تطبيقات الويب الخارجية للجهة بحد أدنى ما يلي: 1-3-15-2 استخدام جدار الحماية لتطبيقات الويب (Web Application Firewall). 2-3-15-2 استخدام مبدأ المعمارية متعددة المستويات (Multi-tier Architecture). 3-3-15-2 استخدام بروتوكولات آمنة (مثل بروتوكول HTTPS). 4-3-15-2 توضيح سياسة الاستخدام الآمن للمستخدمين. 5-3-15-2 التحقق من الهوية على أن يتم تحديد عناصر التحقق المناسبة وعددها وكذلك تقنيات التحقق المناسبة بناء على نتائج تقييم الأثر المحتمل لفشل عملية التحقق وتخطيها، وذلك لعمليات دخول المستخدمين.', '2-15', 60, '28'],
    ['2-15-4', 'Web application protection requirements review', 'مراجعة متطلبات حماية تطبيقات الويب', 'Cybersecurity requirements for protection of web applications of the entity shall be periodically reviewed.', 'يجب مراجعة متطلبات الأمن السيبراني لحماية تطبيقات الويب للجهة من المخاطر السيبرانية دورياً.', '2-15', 61, '28'],
];
